// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Helper function to get weather icon/emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sun') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain') || conditionLower.includes('wet')) return '🌧️';
    if (conditionLower.includes('snow') || conditionLower.includes('ice')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('night')) return '🌙';
    return '🌤️'; // default
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Main Weather Card */}
        <Card shadow="lg" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-6)">
            {/* Header with city name */}
            <Box>
              <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>
            </Box>

            {/* Current Weather Section */}
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-6)">
              {/* Large weather icon and temperature */}
              <Stack align="center" gap="var(--ggui-spacing-3)">
                <Box>
                  <Text size="4xl" color="var(--ggui-color-primary-600)">{getWeatherEmoji(props.condition)}</Text>
                </Box>
                <Box>
                  <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">{props.temperature}°{props.unit}</Text>
                </Box>
              </Stack>

              {/* Condition and details */}
              <Divider orientation="vertical" margin="var(--ggui-spacing-3)" />

              <Stack gap="var(--ggui-spacing-4)">
                <Box>
                  <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.condition}</Text>
                </Box>

                {/* Humidity and Wind Speed */}
                <Stack gap="var(--ggui-spacing-3)">
                  <Row align="center" gap="var(--ggui-spacing-2)">
                    <Icon name="droplet" size={20} color="var(--ggui-color-primary-500)" />
                    <Text color="var(--ggui-color-onSurfaceVariant)">Humidity: <Text as="span" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text></Text>
                  </Row>
                  <Row align="center" gap="var(--ggui-spacing-2)">
                    <Icon name="wind" size={20} color="var(--ggui-color-primary-500)" />
                    <Text color="var(--ggui-color-onSurfaceVariant)">Wind Speed: <Text as="span" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text></Text>
                  </Row>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast Section */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Box>
                <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
              </Box>

              <Row gap="var(--ggui-spacing-3)" wrap justify="between">
                {props.forecast.map((day, index) => (
                  <Card key={index} shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border background="var(--ggui-color-surfaceVariant)" style={{ flex: '0 1 calc(20% - 12px)', minWidth: '100px' }}>
                    <Stack align="center" gap="var(--ggui-spacing-2)">
                      {/* Day name */}
                      {day.day && (
                        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">{day.day}</Text>
                      )}

                      {/* Weather icon/emoji */}
                      {day.icon && (
                        <Box>
                          <Text size="2xl">{day.icon}</Text>
                        </Box>
                      )}

                      {/* High and low temps */}
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        {day.high !== undefined && (
                          <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)">H: {day.high}°{props.unit}</Text>
                        )}
                        {day.low !== undefined && (
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">L: {day.low}°{props.unit}</Text>
                        )}
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

