}

// Color categories for periodic table elements
const ELEMENT_CATEGORIES: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-primary-100)',
  'alkaline earth metal': 'var(--ggui-color-primary-200)',
  'transition metal': 'var(--ggui-color-warning-100)',
  'lanthanide': 'var(--ggui-color-success-100)',
  'actinide': 'var(--ggui-color-success-200)',
  'nonmetal': 'var(--ggui-color-info-100)',
  'metalloid': 'var(--ggui-color-error-100)',
  'halogen': 'var(--ggui-color-warning-200)',
  'noble gas': 'var(--ggui-color-info-200)',
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number } | undefined>(undefined);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query)) ||
      (el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories from elements
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  const handleElementClick = useCallback((element: { atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }) => {
    setSelectedElement(element);
  }, []);

  const getCategoryColor = (category?: string): string => {
    if (!category) return 'var(--ggui-color-surfaceVariant)';
    return ELEMENT_CATEGORIES[category.toLowerCase()] || 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Interactive periodic table. Click an element to view details.
          </Text>
        </Stack>

        {/* Search input */}
         <SearchField
           value={searchQuery}
           onChange={setSearchQuery}
           placeholder="Search by name or symbol..."
           size="md"
         />

        {/* Legend */}
        {categories.length > 0 && (
          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Legend</Text>
              <Row gap="var(--ggui-spacing-4)" wrap>
                {categories.map(cat => (
                  <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                    <Box
                      padding="var(--ggui-spacing-2)"
                      background={getCategoryColor(cat)}
                      borderRadius="var(--ggui-shape-radius-sm)"
                      style={{ minWidth: '16px', minHeight: '16px' }}
                    />
                    <Text variant="bodySmall">{cat}</Text>
                  </Row>
                ))}
              </Row>
            </Stack>
          </Box>
        )}

        {/* CSS Grid periodic table */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-surface)"
          borderRadius="var(--ggui-shape-radius-lg)"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
          }}
        >
          {filteredElements.map(element => {
            const isSelected = selectedElement && selectedElement.atomicNumber === element.atomicNumber;
            const bgColor = getCategoryColor(element.category);
            return (
              <Card
                key={element.atomicNumber}
                as={Clickable}
                onClick={() => handleElementClick(element)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                radius="md"
                border={isSelected}
                style={{
                  gridRow: element.row ?? 'auto',
                  gridColumn: element.col ?? 'auto',
                  background: bgColor,
                  cursor: 'pointer',
                  transition: 'all 0.2s ease-in-out',
                  borderWidth: isSelected ? '2px' : '1px',
                  borderColor: isSelected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)',
                  opacity: searchQuery && !filteredElements.find(e => e.atomicNumber === element.atomicNumber) ? 0.3 : 1,
                }}
              >
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="left">
                    {element.atomicNumber}
                  </Text>
                  <Text
                    variant="label"
                    size="xl"
                    weight="bold"
                    align="center"
                    color="var(--ggui-color-onSurface)"
                  >
                    {element.symbol}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* Detail panel */}
        {/* Detail panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row gap="var(--ggui-spacing-4)" align="center">
                <Box
                  padding="var(--ggui-spacing-4)"
                  background={getCategoryColor(selectedElement.category)}
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ minWidth: '80px', minHeight: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                >
                  <Text
                    variant="label"
                    size="3xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                  >
                    {selectedElement.symbol}
                  </Text>
                </Box>
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Badge variant="primary" size="md">{selectedElement.category}</Badge>
                </Stack>
              </Row>
              <Divider margin="var(--ggui-spacing-3)" />
              <Row gap="var(--ggui-spacing-6)" wrap>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                  <Text variant="body" weight="medium" color="var(--ggui-color-onSurface)">{selectedElement.atomicNumber}</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                  <Text variant="body" weight="medium" color="var(--ggui-color-onSurface)">{selectedElement.atomicWeight?.toFixed(3) ?? 'N/A'}</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)">

              </Row>
              <Row gap="var(--ggui-spacing-2)" justify="end">
                <Button variant="outline" onClick={() => setSelectedElement(undefined)}>Close</Button>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Empty state */}
        {filteredElements.length === 0 && (
          <Alert variant="info" title="No results">
            No elements match your search query. Try a different name or symbol.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

