// Helper component for specification table
function SpecificationTable({ specs }: { specs: unknown[] }) {
  if (!specs || specs.length === 0) {
    return <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>;
  }
  const specArray = specs as { key?: string; value?: string }[];
  return (
    <Table
      columns={[
        { key: 'key', header: 'Property', align: 'left' },
        { key: 'value', header: 'Value', align: 'left' },
      ]}
      data={specArray}
      compact
    />
  );
}

// Helper component for reviews list
function ReviewsList({ reviews }: { reviews: unknown[] }) {
  if (!reviews || reviews.length === 0) {
    return <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">No reviews yet</Text>;
  }
  const reviewArray = reviews as { author?: string; rating?: number; text?: string; date?: string }[];
  return (
