export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Data access with fallbacks
  const productId = props.product?.id || '';
  const productName = props.product?.name || 'Product';
  const price = props.product?.price || 0;
  const currency = props.product?.currency || 'USD';
  const rating = props.product?.rating || 0;
  const reviewCount = props.product?.reviewCount || 0;
  const stock = props.product?.stock || 0;
  const description = props.product?.description || '';
  const specifications = props.product?.specifications || [];
  const reviews = props.product?.reviews || [];

  // Computed values
  const stockStatus = stock === 0 ? 'out-of-stock' : stock < 10 ? 'low-stock' : 'in-stock';
  const isOutOfStock = stock === 0;
  const maxQuantity = stock;
  const formattedPrice = new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency,
  }).format(price);

  // Handlers
  const handleIncrement = useCallback(() => {
    if (quantity < maxQuantity) {
      setQuantity(q => q + 1);
    }
  }, [quantity, maxQuantity]);

  const handleDecrement = useCallback(() => {
    if (quantity > 1) {
      setQuantity(q => q - 1);
    }
  }, [quantity]);

  const handleAddToCart = useCallback(() => {
    if (!isOutOfStock && productId) {
      addToCart({ productId, quantity });
    }
  }, [isOutOfStock, productId, quantity, addToCart]);

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface)">{description || 'No description available'}</Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: <SpecificationTable specs={specifications} />,
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: <ReviewsList reviews={reviews} />,
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock Status */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            width="300px"
            height="300px"
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-6)"
            style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}
          >
            <Text variant="bodyLarge" color="var(--ggui-color-primary-600)" align="center" weight="semibold">
              {productName}
            </Text>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
            {/* Title */}
            <Heading level={1} color="var(--ggui-color-onSurface)">{productName}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" size="2xl" weight="bold" color="var(--ggui-color-primary-600)">
              {formattedPrice}
            </Text>

            {/* Rating */}
            <Row gap="var(--ggui-spacing-3)" align="center">
              <RatingStars rating={rating} />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {rating.toFixed(1)} ({reviewCount} reviews)
              </Text>
            </Row>

            {/* Stock Status Badge */}
            <Box>
              {stockStatus === 'in-stock' && (
                <Badge variant="success" size="md">In Stock</Badge>
              )}
              {stockStatus === 'low-stock' && (
                <Badge variant="warning" size="md">Low Stock</Badge>
              )}
              {stockStatus === 'out-of-stock' && (
                <Badge variant="error" size="md">Out of Stock</Badge>
              )}
            </Box>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Stack gap="var(--ggui-spacing-4)">
          <Tabs items={tabItems} activeKey={activeTab} onChange={setActiveTab} variant="line" />
        </Stack>

        {/* BOTTOM SECTION: Quantity Selector & Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurface)">Quantity</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleDecrement}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Text variant="label" size="base" weight="semibold" style={{ minWidth: '40px', textAlign: 'center' }}>
                  {quantity}
                </Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleIncrement}
                  disabled={quantity >= maxQuantity || isOutOfStock}
                >
                  +
                </Button>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

