  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messageInput, setMessageInput] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [activeTypingSender, setActiveTypingSender] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Handle incoming stream messages
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setActiveTypingSender(typing.latest.sender || 'Someone');
      } else {
        setActiveTypingSender(null);
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (messageInput.trim()) {
      sendMessage({
        text: messageInput,
        timestamp: new Date().toISOString(),
      });
      setMessageInput('');
    }
  }, [messageInput, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    return allMessages.reduce((acc, msg) => {
      if (acc.length > 0 && acc[acc.length - 1][0].sender === msg.sender) {
        acc[acc.length - 1].push(msg);
      } else {
        acc.push([msg]);
      }
      return acc;
    }, [] as typeof allMessages[]);
  }, [allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg" style={{ display: 'flex', flexDirection: 'column', height: '100vh', maxHeight: '90vh' }}>
        {/* Header */}
        <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4)" style={{ paddingBottom: 'var(--ggui-spacing-4)', borderBottom: `1px solid var(--ggui-color-outline)` }}>
          <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
          <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
        </Stack>

        {/* Message List */}
        <Stack
          gap="var(--ggui-spacing-4)"
          style={{
            flex: 1,
            overflowY: 'auto',
            paddingTop: 'var(--ggui-spacing-4)',
            paddingBottom: 'var(--ggui-spacing-4)',
          }}
        >
           {groupedMessages.length === 0 ? (
             <Text color="var(--ggui-color-onSurfaceVariant)" align="center" style={{ marginTop: 'var(--ggui-spacing-8)' }}>
               No messages yet. Start the conversation!
             </Text>
           ) : (
             groupedMessages.map((group, groupIndex) => {
               const sender = group[0].sender || 'Unknown';
               const isCurrentUser = sender === props.currentUser;

               return (
                 <Box key={groupIndex}>
                   {group.map((msg, msgIndex) => (
                     <Stack
                       key={msgIndex}
                       direction="horizontal"
                       align="end"
                       justify={isCurrentUser ? 'end' : 'start'}
                       gap="var(--ggui-spacing-2)"
                       style={{ marginBottom: 'var(--ggui-spacing-2)' }}
                     >
                       {!isCurrentUser && msgIndex === 0 && (
                         <Avatar name={sender} size="sm" />
                       )}
                       {!isCurrentUser && msgIndex > 0 && (
                         <Box style={{ width: '32px' }} />
                       )}

                       <Box
                         padding="var(--ggui-spacing-3)"
                         background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                         borderRadius="var(--ggui-shape-radius-lg)"
                         style={{ maxWidth: '60%' }}
                       >
                         {msgIndex === 0 && !isCurrentUser && (
                           <Text variant="label" color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurfaceVariant)'} style={{ marginBottom: 'var(--ggui-spacing-1)' }}>
                             {sender}
                           </Text>
                         )}
                         <Text color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}>{msg.text || ''}</Text>
                         <Text
                           variant="caption"
                           color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                           style={{ marginTop: 'var(--ggui-spacing-1)' }}
                         >
                           {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                         </Text>
                       </Box>
                     </Stack>
                   ))}
                 </Box>
               );
             })
           )}
          {activeTypingSender && (
            <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2)">
              <Avatar name={activeTypingSender} size="sm" />
              <Box
                padding="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
              >
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ fontStyle: 'italic' }}>
                  {activeTypingSender} is typing...
                </Text>
              </Box>
            </Stack>
          )}

          <div ref={messagesEndRef} />
        </Stack>

        {/* Input Area */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end" style={{ paddingTop: 'var(--ggui-spacing-4)', borderTop: `1px solid var(--ggui-color-outline)` }}>
          <Input
            label="Message"
            placeholder="Type a message..."
            value={messageInput}
            onChange={setMessageInput}
            onKeyDown={handleKeyDown}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            onClick={handleSendMessage}
            disabled={!messageInput.trim()}
            size="md"
            rightIcon={<Icon name="send" size={16} />}
          >
            Send
          </Button>
        </Stack>
      </Card>
    </Container>
  );
}

