// Merge displayed stocks with latest stream updates
interface MergedStock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State
  const [displayedStocks, setDisplayedStocks] = useState<MergedStock[]>([]);
  const [lastUpdateTime, setLastUpdateTime] = useState<Date | null>(null);
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);



  // Initialize displayed stocks from props
  useEffect(() => {
    if (props.stocks && props.stocks.length > 0) {
      setDisplayedStocks(props.stocks.map(s => ({ ...s })));
    }
  }, [props.stocks]);

  // Handle price updates from stream
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      if (update.symbol) {
        setDisplayedStocks(prev => {
          const updated = prev.map(stock =>
            stock.symbol === update.symbol
              ? {
                  ...stock,
                  price: update.price ?? stock.price,
                  change: update.change ?? stock.change,
                  changePercent: update.changePercent ?? stock.changePercent,
                }
              : stock
          );
          return updated;
        });

        // Mark as updating and highlight
        setUpdatingSymbols(prev => new Set([...prev, update.symbol]));
        setLastUpdateTime(new Date());

        // Clear updating flag after animation
        if (updateTimeoutRef.current) clearTimeout(updateTimeoutRef.current);
        updateTimeoutRef.current = setTimeout(() => {
          setUpdatingSymbols(prev => {
            const next = new Set(prev);
            next.delete(update.symbol);
            return next;
          });
        }, 1000);
      }
    }
  }, [priceUpdate.latest]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (updateTimeoutRef.current) clearTimeout(updateTimeoutRef.current);
    };
  }, []);

  const isMarketOpen = marketStatus.latest?.status === 'open';
  const marketStatusLabel = marketStatus.latest?.status || 'unknown';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated:
              </Text>
              <Text
                variant="caption"
                weight="semibold"
                color={isMarketOpen ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-onSurfaceVariant)'}
              >
                {lastUpdateTime
                  ? lastUpdateTime.toLocaleTimeString()
                  : 'Never'}
              </Text>
            </Stack>
          </Stack>
          <Badge
            variant={isMarketOpen ? 'success' : 'default'}
            size="md"
          >
            {marketStatusLabel === 'open'
              ? '🟢 Market Open'
              : marketStatusLabel === 'closed'
              ? '🔴 Market Closed'
              : marketStatusLabel === 'pre-market'
              ? '🟡 Pre-Market'
              : '🟡 After-Hours'}
          </Badge>
        </Stack>

        {/* Stock Grid */}
        {displayedStocks.length > 0 ? (
         <div style={{
           display: 'grid',
           gridTemplateColumns: 'repeat(3, 1fr)',
           gap: 'var(--ggui-spacing-4)',
           '@media (max-width: 768px)': {
             gridTemplateColumns: '1fr',
           },
         }}>
            {displayedStocks.map((stock) => (
              <StockCard
                key={stock.symbol || 'unknown'}
                stock={stock}
                isUpdating={updatingSymbols.has(stock.symbol || '')}
              />
            ))}
          </div>
        ) : (
          <Card padding="var(--ggui-spacing-6)" shadow="md" border>
            <Stack align="center" justify="center" gap="var(--ggui-spacing-2)">
              <Icon name="inbox" size={48} color="var(--ggui-color-onSurfaceVariant)" />
              <Text color="var(--ggui-color-onSurfaceVariant)">No stocks to display</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

