      setCurrentStep(3);
    }
  }, [currentStep, isStep1Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((currentStep - 1) as 1 | 2 | 3);
    }
  }, [currentStep]);

