              <Divider margin="var(--ggui-spacing-3)" />

              {/* Summary Section */}
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Profile Summary */}
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" marginBottom="var(--ggui-spacing-1)" display="block">
                      Profile
                    </Text>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Row gap="var(--ggui-spacing-2)" align="center">
                        <Text size="2xl">{formData.avatar}</Text>
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="body" weight="medium">
                            {formData.name}
                          </Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {formData.email}
                          </Text>
                        </Stack>
                      </Row>
                    </Stack>
                  </Box>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Preferences Summary */}
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" marginBottom="var(--ggui-spacing-2)" display="block">
                      Preferences
                    </Text>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between" align="center">
                        <Text variant="body">Role:</Text>
                        <Badge variant="primary">{formData.role}</Badge>
                      </Row>
                      <Row justify="between" align="center">
                        <Text variant="body">Email Notifications:</Text>
                        <Badge variant={formData.emailNotifications ? 'success' : 'default'}>
                          {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                        </Badge>
                      </Row>
                      <Row justify="between" align="center">
                        <Text variant="body">Theme:</Text>
                        <Badge variant="secondary">
                          {formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}
                        </Badge>
                      </Row>
                    </Stack>
                  </Box>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Box width="100%" maxWidth="600px">
          <Row gap="var(--ggui-spacing-3)" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={handleBack}
              disabled={currentStep === 1}
            >
              Back
            </Button>
            <Spacer size="flex" />
            {currentStep < 3 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={currentStep === 1 ? !isStep1Valid : false}
              >
                Next
              </Button>
            )}
            {currentStep === 3 && (
              <Button
                variant="primary"
                onClick={handleComplete}
                disabled={!isStep1Valid}
              >
                Complete Setup
              </Button>
            )}
          </Row>
        </Box>
      </Stack>
    </Container>
  );
}
}
